### 3. MRL Truncation Tests (CRITICAL for static-mrl)
```rust
#[test]
fn test_mrl_truncation_produces_correct_length() {
    let embedder = static_mrl_embedder();
    let full = embedder.embed("test sentence for MRL").unwrap();
    assert_eq!(full.len(), 1024, "Full embedding should be 1024 dims");

    for dims in [64, 128, 256, 512, 768] {
        let truncated = embedder.truncate(&[full.clone()], dims).unwrap();
        assert_eq!(truncated[0].len(), dims,
            "Truncated embedding should be {} dims", dims);
    }
}

#[test]
fn test_mrl_renormalization_after_truncation() {
    // CRITICAL TEST: After MRL truncation, vectors MUST be re-normalized to unit length.
    // Without re-normalization, cosine similarity computations will be incorrect
    // because the truncated prefix of a unit vector is NOT itself a unit vector.
    let embedder = static_mrl_embedder();
    let full = embedder.embed("test re-normalization").unwrap();

    // Verify full embedding is normalized
    let full_norm: f32 = full.iter().map(|x| x * x).sum::<f32>().sqrt();
    assert!((full_norm - 1.0).abs() < 0.01, "Full embedding norm: {}", full_norm);

    // Truncated prefix of a normalized vector is NOT normalized (unless by coincidence)
    // The truncate() method MUST re-normalize
    for dims in [64, 128, 256, 512, 768] {
        let truncated = embedder.truncate(&[full.clone()], dims).unwrap();
        let trunc_norm: f32 = truncated[0].iter().map(|x| x * x).sum::<f32>().sqrt();

        tracing::info!(
            dims = dims,
            truncated_norm = trunc_norm,
            "MRL re-normalization check"
        );

        assert!((trunc_norm - 1.0).abs() < 0.01,
            "Truncated to {} dims: norm should be 1.0, got {}. \
             Re-normalization is REQUIRED after MRL truncation!", dims, trunc_norm);
    }
}

#[test]
fn test_mrl_truncation_is_prefix() {
    // MRL works by using the first N dimensions of the full embedding.
    // Before re-normalization, the truncated values should match the prefix.
    let embedder = static_mrl_embedder();
    let full = embedder.embed("prefix test").unwrap();

    // Get truncated (which is re-normalized)
    let truncated_256 = embedder.truncate(&[full.clone()], 256).unwrap();

    // Compute what the raw prefix would be (before re-normalization)
    let raw_prefix: Vec<f32> = full[..256].to_vec();
    let prefix_norm: f32 = raw_prefix.iter().map(|x| x * x).sum::<f32>().sqrt();
    let normalized_prefix: Vec<f32> = raw_prefix.iter().map(|x| x / prefix_norm).collect();

    // The truncated result should match the normalized prefix
    let diff: f32 = truncated_256[0].iter().zip(normalized_prefix.iter())
        .map(|(a, b)| (a - b).abs())
        .sum();
    assert!(diff < 0.001,
        "Truncated should be normalized prefix, diff={}", diff);
}

#[test]
fn test_mrl_quality_degrades_gracefully() {
    let embedder = static_mrl_embedder();
    let q = embedder.embed("coffee espresso latte").unwrap();
    let d1 = embedder.embed("best cafe downtown morning brew").unwrap();
    let d2 = embedder.embed("quantum mechanics wave function").unwrap();

    // Quality should degrade gracefully with fewer dimensions
    let mut prev_margin = f64::MAX;
    for dims in [64, 128, 256, 512, 768, 1024] {
        let qt = embedder.truncate(&[q.clone()], dims).unwrap();
        let d1t = embedder.truncate(&[d1.clone()], dims).unwrap();
        let d2t = embedder.truncate(&[d2.clone()], dims).unwrap();

        let sim_good = cosine_similarity(&qt[0], &d1t[0]);
        let sim_bad = cosine_similarity(&qt[0], &d2t[0]);
        let margin = (sim_good - sim_bad) as f64;

        tracing::info!(
            dims = dims,
            sim_relevant = sim_good,
            sim_irrelevant = sim_bad,
            margin = margin,
            "MRL quality at reduced dimensions"
        );

        assert!(sim_good > sim_bad,
            "Relevance ordering broken at dims={}: {} vs {}", dims, sim_good, sim_bad);
    }
}

