### 4. Model2Vec Specific Tests (Static Lookup)
```rust
#[test]
fn test_model2vec_is_pure_lookup() {
    // Model2Vec uses static token embeddings (no ONNX, no attention)
    // This means it should be extremely fast
    let embedder = model2vec_embedder();

    // Warmup
    for _ in 0..5 { embedder.embed("warmup").unwrap(); }

    let start = Instant::now();
    for _ in 0..1000 {
        embedder.embed("static lookup speed test").unwrap();
    }
    let avg_us = start.elapsed().as_micros() as f64 / 1000.0;

    tracing::info!(avg_us = avg_us, "Model2Vec per-embed latency");
    // Should be sub-millisecond (pure lookup + mean pool + normalize)
    assert!(avg_us < 1000.0,
        "Model2Vec should be <1ms per embed, got {}us", avg_us);
}

#[test]
fn test_model2vec_mean_pooling() {
    let embedder = model2vec_embedder();

    // Same words in different order should produce same embedding
    // (mean pooling is order-invariant for bag-of-words)
    let e1 = embedder.embed("hello world foo").unwrap();
    let e2 = embedder.embed("world foo hello").unwrap();

    let sim = cosine_similarity(&e1, &e2);
    tracing::info!(sim = sim, "Model2Vec order invariance");
    // Note: tokenization may differ, so exact equality is not guaranteed
    // but they should be very similar
    assert!(sim > 0.9, "Mean pooling should be mostly order-invariant: {}", sim);
}

#[test]
fn test_model2vec_unknown_tokens() {
    let embedder = model2vec_embedder();
    // Made-up words should still produce valid embeddings
    // (subword tokenization will break them into known pieces)
    let result = embedder.embed("xyzzy plugh zork");
    assert!(result.is_ok(), "Unknown tokens should be handled");
    let embedding = result.unwrap();
    assert_eq!(embedding.len(), 256);
    let norm: f32 = embedding.iter().map(|x| x * x).sum::<f32>().sqrt();
    assert!((norm - 1.0).abs() < 0.1, "Should still be approximately normalized: {}", norm);
}
