### 1. TwoTierSearcher

```rust
pub struct TwoTierSearcher {
    /// Fast embedder for instant results (Model2Vec, in-process)
    fast: Model2VecEmbedder,
    /// Quality embedder via daemon (MiniLM, warm process)  
    quality: DaemonClient,
    /// Blend factor for combining scores (0.0 = fast only, 1.0 = quality only)
    blend_factor: f32,
}

pub enum SearchPhase {
    /// Initial fast results (sub-millisecond)
    Initial { results: Vec<SearchResult>, latency_ms: f64 },
    /// Refined results from transformer
    Refined { results: Vec<SearchResult>, latency_ms: f64, changes: RankChanges },
    /// Refinement failed, keeping initial results
    RefinementFailed { error: String },
}

pub struct RankChanges {
    /// Items that moved up
    promoted: Vec<(usize, usize)>,  // (old_rank, new_rank)
    /// Items that moved down
    demoted: Vec<(usize, usize)>,
    /// Items unchanged
    stable: usize,
}
