### 2. Async Search Stream

```rust
impl TwoTierSearcher {
    /// Returns a stream of search phases
    pub fn search(&self, query: &str, limit: usize) -> impl Stream<Item = SearchPhase> {
        async_stream::stream! {
            let start = Instant::now();

            // Phase 1: Fast results (blocking, but sub-ms)
            let fast_emb = self.fast.embed(query)?;
            let initial = self.rank_documents(&fast_emb, limit);
            yield SearchPhase::Initial { 
                results: initial.clone(),
                latency_ms: start.elapsed().as_secs_f64() * 1000.0,
            };

            // Phase 2: Quality refinement (async, ~130ms)
            let refine_start = Instant::now();
            match self.quality.embed(&[query], Some("all-MiniLM-L6-v2"), None).await {
                Ok(embeddings) => {
                    let quality_emb = &embeddings[0];
                    let refined = self.rank_documents(quality_emb, limit);
                    let changes = compute_rank_changes(&initial, &refined);

                    yield SearchPhase::Refined {
                        results: refined,
                        latency_ms: refine_start.elapsed().as_secs_f64() * 1000.0,
                        changes,
                    };
                }
                Err(e) => {
                    yield SearchPhase::RefinementFailed { 
                        error: e.to_string() 
                    };
                }
            }
        }
    }
}
