## Purpose
Provide a speed/quality baseline for static embeddings. Model2Vec uses a distilled
word2vec-style approach: subword tokenization + static lookup + mean pooling.
No transformer inference required - extremely fast.

## Architecture
```rust
pub struct Model2VecEmbedder {
    /// Subword vocabulary (BPE or WordPiece from teacher model)
    tokenizer: tokenizers::Tokenizer,
    /// Static embedding matrix [vocab_size × dims]
    embeddings: ndarray::Array2<f32>,
    /// Output dimensions (256 for potion-retrieval-32M)
    dimensions: usize,
    /// Model identifier
    name: String,
}

impl Embedder for Model2VecEmbedder {
    fn embed_batch(&self, texts: &[&str]) -> Result<Vec<Vec<f32>>> {
        texts.par_iter().map(|text| {
            // 1. Tokenize with subword tokenizer
            let encoding = self.tokenizer.encode(text, false)?;
            let token_ids = encoding.get_ids();

            // 2. Look up static embeddings for each subword
            // 3. Mean pool across subwords (ignoring OOV/pad)
            // 4. L2 normalize
            let mut sum = vec![0.0f32; self.dimensions];
            let mut count = 0usize;
            for &id in token_ids {
                if (id as usize) < self.embeddings.nrows() {
                    let row = self.embeddings.row(id as usize);
                    for (s, &r) in sum.iter_mut().zip(row.iter()) {
                        *s += r;
                    }
                    count += 1;
                }
            }
            if count > 0 {
                let inv = 1.0 / count as f32;
                for s in &mut sum { *s *= inv; }
            }
            // L2 normalize
            let norm = sum.iter().map(|x| x * x).sum::<f32>().sqrt();
            if norm > 0.0 {
                for s in &mut sum { *s /= norm; }
            }
            Ok(sum)
        }).collect()
    }

    fn dimensions(&self) -> usize { self.dimensions }
    fn model_name(&self) -> &str { &self.name }
    fn supports_mrl(&self) -> bool { false } // Model2Vec doesn't support MRL
}
```

